import java.util.ArrayList;
import java.util.Arrays;
import java.util.PriorityQueue;

public class Solution {

    // Class to represent an edge in the graph for Dijkstra's algorithm
    static class Edge {
        int to;
        long weight;

        public Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    // Class to represent a state in the priority queue for Dijkstra's algorithm
    static class State implements Comparable<State> {
        int node;
        long distance;

        public State(int node, long distance) {
            this.node = node;
            this.distance = distance;
        }

        @Override
        public int compareTo(State other) {
            return Long.compare(this.distance, other.distance);
        }
    }

    /**
     * Calculates the minimum cost for each shop to obtain apples.
     * 
     * @param n The number of shops.
     * @param prices The prices of apples at each shop.
     * @param roads The list of roads.
     * @return An array where ans[i] is the minimum total cost for shop i.
     */
    public static long[] solve(long n, long[] prices, long[][] roads) {
        int N = (int) n;

        // Step 1: Calculate shortest paths from all nodes to all other nodes 
        // for 'empty-handed' travel (Cost = cost_i).
        // dist_empty[i][j] = shortest path cost from i to j without apples.
        long[][] dist_empty = new long[N][N];
        for (int i = 0; i < N; i++) {
            Arrays.fill(dist_empty[i], Long.MAX_VALUE);
            dist_empty[i][i] = 0;
        }

        // Build the adjacency list for empty-handed travel
        ArrayList<Edge>[] adjEmpty = new ArrayList[N];
        for (int i = 0; i < N; i++) {
            adjEmpty[i] = new ArrayList<>();
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            // Roads are bidirectional for empty travel
            adjEmpty[u].add(new Edge(v, cost));
            adjEmpty[v].add(new Edge(u, cost));
        }

        // Run Dijkstra from every node for empty-handed travel
        for (int startNode = 0; startNode < N; startNode++) {
            long[] dist = new long[N];
            Arrays.fill(dist, Long.MAX_VALUE);
            dist[startNode] = 0;

            PriorityQueue<State> pq = new PriorityQueue<>();
            pq.add(new State(startNode, 0));

            while (!pq.isEmpty()) {
                State current = pq.poll();
                int u = current.node;
                long d = current.distance;

                if (d > dist[u]) continue;

                for (Edge edge : adjEmpty[u]) {
                    int v = edge.to;
                    long weight = edge.weight;

                    if (dist[u] != Long.MAX_VALUE && dist[u] + weight < dist[v]) {
                        dist[v] = dist[u] + weight;
                        pq.add(new State(v, dist[v]));
                    }
                }
            }
            // Store the results for empty travel (i -> j)
            for(int j=0; j<N; j++){
                dist_empty[startNode][j] = dist[j];
            }
        }


        // Step 2: Calculate shortest paths from all nodes to all other nodes 
        // for 'carrying-apples' travel (Cost = cost_i * tax_i).
        // dist_carried[i][j] = shortest path cost from i to j while carrying apples.
        long[][] dist_carried = new long[N][N];
        for (int i = 0; i < N; i++) {
            Arrays.fill(dist_carried[i], Long.MAX_VALUE);
            dist_carried[i][i] = 0;
        }

        // Build the adjacency list for carrying-apples travel
        ArrayList<Edge>[] adjCarried = new ArrayList[N];
        for (int i = 0; i < N; i++) {
            adjCarried[i] = new ArrayList<>();
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];
            long taxed_cost = cost * tax;

            // Roads are bidirectional for carrying apples
            adjCarried[u].add(new Edge(v, taxed_cost));
            adjCarried[v].add(new Edge(u, taxed_cost));
        }

        // Run Dijkstra from every node for carried-apples travel
        for (int startNode = 0; startNode < N; startNode++) {
            long[] dist = new long[N];
            Arrays.fill(dist, Long.MAX_VALUE);
            dist[startNode] = 0;

            PriorityQueue<State> pq = new PriorityQueue<>();
            pq.add(new State(startNode, 0));

            while (!pq.isEmpty()) {
                State current = pq.poll();
                int u = current.node;
                long d = current.distance;

                if (d > dist[u]) continue;

                for (Edge edge : adjCarried[u]) {
                    int v = edge.to;
                    long weight = edge.weight;

                    if (dist[u] != Long.MAX_VALUE && dist[u] + weight < dist[v]) {
                        dist[v] = dist[u] + weight;
                        pq.add(new State(v, dist[v]));
                    }
                }
            }
            // Store the results for carried travel (j -> i)
            // We need dist_carried[j][i] if we are going from j (buy) to i (return)
            for(int j=0; j<N; j++){
                dist_carried[j][i] = dist[j]; // Wait, we need to be careful here.
            }

            // Let's redefine: We want the cost from J (purchase location) to I (final location) carrying apples.
            // Dijkstra starting at J gives dist[I] = shortest path cost J -> I while carrying apples.
            // So, dist_carried[J][I] = dist[I] when Dijkstra starts at J.
            for(int j=0; j<N; j++){
                dist_carried[j][j] = 0; // Redundant but safe
            }
            // Correct assignment: dist_carried[startNode][j] = dist[j]
            for(int j=0; j<N; j++){
                 dist_carried[startNode][j] = dist[j];
            }
        }


        // Step 3: Calculate the minimum total cost for each shop i
        long[] ans = new long[N];

        for (int i = 0; i < N; i++) {
            // Option 1: Buy directly at shop i
            long minCost = prices[i];

            // Option 2: Travel empty-handed to shop j, buy at j, travel back to i with apples.
            // Total cost = (Empty path cost i -> j) + prices[j] + (Carried path cost j -> i)
            for (int j = 0; j < N; j++) {
                if (i == j) continue;

                // Cost 1: Empty travel from i to j
                long cost_i_to_j_empty = dist_empty[i][j];

                // Cost 2: Carried travel from j to i
                long cost_j_to_i_carried = dist_carried[j][i];

                if (cost_i_to_j_empty != Long.MAX_VALUE && cost_j_to_i_carried != Long.MAX_VALUE) {
                    // Total cost = Cost(i->j, empty) + Price[j] + Cost(j->i, carried)
                    long totalCost = cost_i_to_j_empty + prices[j] + cost_j_to_i_carried;
                    minCost = Math.min(minCost, totalCost);
                }
            }
            ans[i] = minCost;
        }

        return ans;
    }
}
