import java.util.*;

public class Solution {
    /**
     * Calculates the minimum total cost to buy an apple for each store i.
     * For each store i, the cost is min(prices[i], min_j (dist_empty(i, j) + dist_loaded(j, i)) + prices[j]).
     *
     * @param n The number of stores.
     * @param prices The prices of apples at each store.
     * @param roads The road connections.
     * @return An array where ans[i] is the minimum cost for store i.
     */
    public static long[] solve(long n, long[] prices, long[][] roads) {
        int N = (int) n;

        // --- Step 1: Calculate minimum cost to travel from any node to any other node when empty-handed (Cost = cost_i) ---
        // distEmpty[i][j]: shortest path cost from i to j when empty-handed.
        // Since roads are bidirectional and costs are non-negative, we can use Floyd-Warshall or run Dijkstra from every node.
        // Given N <= 1000, Floyd-Warshall O(N^3) might be too slow (10^9 operations). Dijkstra from N sources O(N * (E + N log N)) is better.
        // E <= 2000. N * (2000 + 1000 log 1000) approx 1000 * (2000 + 10000) = 12 million operations, which is fine.

        long INF = Long.MAX_VALUE / 2; // Use a large value for infinity

        // Adjacency list for empty travel (cost = cost_i)
        List<Edge>[] adjEmpty = new List[N];
        for (int i = 0; i < N; i++) {
            adjEmpty[i] = new ArrayList<>();
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            // Roads are bidirectional
            adjEmpty[u].add(new Edge(u, v, cost));
            adjEmpty[v].add(new Edge(v, u, cost));
        }

        // distEmpty[i][j] stores shortest path from i to j (empty)
        long[][] distEmpty = new long[N][N];
        for (int i = 0; i < N; i++) {
            Arrays.fill(distEmpty[i], INF);
            distEmpty[i][i] = 0;
        }

        // Run Dijkstra from every node
        for (int startNode = 0; startNode < N; startNode++) {
            PriorityQueue<Pair> pq = new PriorityQueue<>(Comparator.comparingLong(p -> p.cost));
            pq.offer(new Pair(startNode, 0));
            distEmpty[startNode][startNode] = 0;

            while (!pq.isEmpty()) {
                Pair current = pq.poll();
                int u = current.node;
                long d = current.cost;

                if (d > distEmpty[startNode][u]) continue;

                for (Edge edge : adjEmpty[u]) {
                    int v = edge.to;
                    long weight = edge.weight;
                    if (distEmpty[startNode][u] + weight < distEmpty[startNode][v]) {
                        distEmpty[startNode][v] = distEmpty[startNode][u] + weight;
                        pq.offer(new Pair(v, distEmpty[startNode][v]));
                    }
                }
            }
        }


        // --- Step 2: Calculate minimum cost to travel from any node to any other node when loaded (Cost = cost_i * tax_i) ---
        // distLoaded[j][i]: shortest path cost from j to i when loaded.

        // Adjacency list for loaded travel (cost = cost_i * tax_i)
        List<Edge>[] adjLoaded = new List[N];
        for (int i = 0; i < N; i++) {
            adjLoaded[i] = new ArrayList<>();
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];
            long loadedCost = cost * tax;

            // Roads are bidirectional
            adjLoaded[u].add(new Edge(u, v, loadedCost));
            adjLoaded[v].add(new Edge(v, u, loadedCost));
        }

        // distLoaded[j][i] stores shortest path from j to i (loaded)
        long[][] distLoaded = new long[N][N];
        for (int j = 0; j < N; j++) {
            Arrays.fill(distLoaded[j], INF);
            distLoaded[j][j] = 0;
        }

        // Run Dijkstra from every node j (the purchasing location)
        for (int startNode = 0; startNode < N; startNode++) {
            PriorityQueue<Pair> pq = new PriorityQueue<>(Comparator.comparingLong(p -> p.cost));
            pq.offer(new Pair(startNode, 0));
            distLoaded[startNode][startNode] = 0;

            while (!pq.isEmpty()) {
                Pair current = pq.poll();
                int u = current.node;
                long d = current.cost;

                if (d > distLoaded[startNode][u]) continue;

                for (Edge edge : adjLoaded[u]) {
                    int v = edge.to;
                    long weight = edge.weight;
                    if (distLoaded[startNode][u] + weight < distLoaded[startNode][v]) {
                        distLoaded[startNode][v] = distLoaded[startNode][u] + weight;
                        pq.offer(new Pair(v, distLoaded[startNode][v]));
                    }
                }
            }
        }

        // --- Step 3: Calculate final answer for each store i ---
        long[] ans = new long[N];

        for (int i = 0; i < N; i++) {
            // Option 1: Buy directly at store i
            long minCost = prices[(int) i];

            // Option 2: Travel empty to store j, buy, travel loaded back to i
            for (int j = 0; j < N; j++) {
                if (i == j) continue;

                // Travel empty from i to j: distEmpty[i][j]
                long emptyTripCost = distEmpty[i][j];

                // Travel loaded from j to i: distLoaded[j][i]
                long loadedTripCost = distLoaded[j][i];

                if (emptyTripCost != INF && loadedTripCost != INF) {
                    // Total cost = Empty Trip Cost + Loaded Trip Cost + Price at j
                    long totalCost = emptyTripCost + loadedTripCost + prices[(int) j];
                    minCost = Math.min(minCost, totalCost);
                }
            }
            ans[i] = minCost;
        }

        return ans;
    }

    // Helper class for Dijkstra's algorithm (Node and Cost)
    static class Pair {
        int node;
        long cost;

        public Pair(int node, long cost) {
            this.node = node;
            this.cost = cost;
        }
    }

    // Helper class for Edges in adjacency list
    static class Edge {
        int to;
        long weight;

        public Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }
}
