import java.util.*;

class Solution {
    /**
     * Calculates the minimum total cost to obtain apples at each shop.
     * The cost at shop i is min(prices[i], min_{j != i} (shortest_path_cost(i->j, no_apple) + shortest_path_cost(j->i, with_apple)) + prices[j])).
     * Since the roads are bidirectional, the cost for the return trip from j to i (with apple) is the same as the cost from i to j (with apple) along the reverse path.
     * The shortest path cost without apple is the same as the shortest path cost with apple if we consider the cost structure:
     * Cost(u->v, no_apple) = cost_uv
     * Cost(u->v, with_apple) = cost_uv * tax_uv
     *
     * We need:
     * 1. Shortest path cost from any shop to any other shop without carrying apples (Cost_no_apple[u][v]).
     * 2. Shortest path cost from any shop to any other shop while carrying apples (Cost_with_apple[u][v]).
     *
     * Since roads are bidirectional, the shortest path calculation is symmetric if we only use one cost type.
     *
     * Let D_no[i][j] be the shortest path cost from i to j without apples.
     * Let D_tax[i][j] be the shortest path cost from i to j with apples.
     *
     * For a road [u, v, cost, tax]:
     * Edge (u, v) cost_no = cost. Edge (v, u) cost_no = cost.
     * Edge (u, v) cost_tax = cost * tax. Edge (v, u) cost_tax = cost * tax.
     *
     * We can run Dijkstra's algorithm twice for all pairs, or use Floyd-Warshall. Given N <= 1000, Floyd-Warshall O(N^3) might be too slow (10^9).
     * Dijkstra N times: N * O(E log V) or N * O(V^2). Since E <= 2000, N * O(E log N) is feasible.
     *
     * Let's use Dijkstra from every node.
     *
     * Step 1: Calculate D_no[i][j] for all i, j.
     * Step 2: Calculate D_tax[i][j] for all i, j.
     *
     * The total cost for shop i, if buying at j:
     * Cost = D_no[i][j] + D_tax[j][i] + prices[j]
     *
     * Since the road is bidirectional:
     * D_no[i][j] = D_no[j][i]
     * D_tax[j][i] = D_tax[i][j]
     *
     * Total cost for shop i, buying at j:
     * Cost = D_no[i][j] + D_tax[i][j] + prices[j]
     *
     * Minimum cost for shop i:
     * ans[i] = min(prices[i], min_{j=0..n-1} (D_no[i][j] + D_tax[i][j] + prices[j]))
     */
    public static long[] solve(long n, long[] prices, long[][] roads) {
        int N = (int) n;

        // Adjacency lists for Dijkstra's
        // Node index: 0 to N-1

        // Graph for no apple (cost_no)
        // Edge structure: {neighbor, cost_no}
        List<int[]>[] adjNo = new List[N];
        for (int i = 0; i < N; i++) {
            adjNo[i] = new ArrayList<>();
        }

        // Graph for with apple (cost_tax)
        // Edge structure: {neighbor, cost_tax}
        List<int[]>[] adjTax = new List[N];
        for (int i = 0; i < N; i++) {
            adjTax[i] = new ArrayList<>();
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];

            // Road is bidirectional

            // No apple (u <-> v cost)
            adjNo[u].add(new int[]{(int)v, (int)cost});
            adjNo[v].add(new int[]{(int)u, (int)cost});

            // With apple (u <-> v cost * tax)
            long taxCost = cost * tax;
            adjTax[u].add(new int[]{(int)v, (int)taxCost});
            adjTax[v].add(new int[]{(int)u, (int)taxCost});
        }

        // D_no[i][j]: Shortest path cost from i to j without apples
        long[][] D_no = new long[N][N];
        // D_tax[i][j]: Shortest path cost from i to j with apples
        long[][] D_tax = new long[N][N];

        final long INF = Long.MAX_VALUE / 2; // Safe infinity

        for (int i = 0; i < N; i++) {
            Arrays.fill(D_no[i], INF);
            Arrays.fill(D_tax[i], INF);
        }

        // Dijkstra implementation
        for (int startNode = 0; startNode < N; startNode++) {
            // 1. Dijkstra for D_no from startNode
            long[] distNo = new long[N];
            Arrays.fill(distNo, INF);
            distNo[startNode] = 0;

            // PriorityQueue stores {distance, node}
            PriorityQueue<long[]> pqNo = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
            pqNo.offer(new long[]{0, startNode});

            while (!pqNo.isEmpty()) {
                long[] current = pqNo.poll();
                long d = current[0];
                int u = (int) current[1];

                if (d > distNo[u]) continue;

                for (int[] edge : adjNo[u]) {
                    int v = edge[0];
                    long weight = edge[1];
                    if (distNo[u] + weight < distNo[v]) {
                        distNo[v] = distNo[u] + weight;
                        pqNo.offer(new long[]{distNo[v], v});
                    }
                }
            }

            // 2. Dijkstra for D_tax from startNode
            long[] distTax = new long[N];
            Arrays.fill(distTax, INF);
            distTax[startNode] = 0;

            PriorityQueue<long[]> pqTax = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
            pqTax.offer(new long[]{0, startNode});

            while (!pqTax.isEmpty()) {
                long[] current = pqTax.poll();
                long d = current[0];
                int u = (int) current[1];

                if (d > distTax[u]) continue;

                for (int[] edge : adjTax[u]) {
                    int v = edge[0];
                    long weight = edge[1];
                    if (distTax[u] + weight < distTax[v]) {
                        distTax[v] = distTax[u] + weight;
                        pqTax.offer(new long[]{distTax[v], v});
                    }
                }
            }

            // Store results for startNode
            for (int endNode = 0; endNode < N; endNode++) {
                D_no[startNode][endNode] = distNo[endNode];
                D_tax[startNode][endNode] = distTax[endNode];
            }
        }

        // Final calculation for ans[i]
        long[] ans = new long[N];

        for (int i = 0; i < N; i++) {
            // Option 1: Buy at i directly
            long minCost = prices[i];

            // Option 2: Travel to j, buy at j, travel back to i
            for (int j = 0; j < N; j++) {
                if (i == j) continue; // Already covered by Option 1

                // Cost = D_no[i][j] (travel i->j without apple) + D_tax[j][i] (travel j->i with apple) + prices[j]
                // Since roads are bidirectional, D_tax[j][i] == D_tax[i][j]

                if (D_no[i][j] == INF || D_tax[i][j] == INF) {
                    // Path does not exist
                    continue;
                }

                // Total cost = Travel_out + Price_j + Travel_back
                long totalCost = D_no[i][j] + D_tax[i][j] + prices[j];
                minCost = Math.min(minCost, totalCost);
            }
            ans[i] = minCost;
        }

        return ans;
    }
}
